 26→// ── Statistical helpers ───────────────────────────────────────────────
 27→
 28→export function computeMovingAverage(
 29→  values: number[],
 30→  windowSize: number,
 31→): number | null {
 32→  if (values.length === 0) return null;
 33→  const window = values.slice(-windowSize);
 34→  return window.reduce((a, b) => a + b, 0) / window.length;
 35→}
 36→
 37→export function computeZScore(
 38→  value: number,
 39→  historicalValues: number[],
 40→): number | null {
 41→  if (historicalValues.length < 3) return null;
 42→  const mean =
 43→    historicalValues.reduce((a, b) => a + b, 0) / historicalValues.length;
 44→  const variance =
 45→    historicalValues.reduce((sum, v) => sum + (v - mean) ** 2, 0) /
 46→    historicalValues.length;
 47→  const stddev = Math.sqrt(variance);
 48→  if (stddev === 0) return 0;
 49→  return (value - mean) / stddev;
 50→}
 51→
 52→export function detectAnomalies(
 53→  value: number,
 54→  history: number[],
 55→  metricName: string,
 56→  threshold = 2,
 57→): AnomalyFlag | null {
 58→  const z = computeZScore(value, history);
 59→  if (z === null || Math.abs(z) <= threshold) return null;
 60→  return {
 61→    metric: metricName,
 62→    zScore: Math.round(z * 100) / 100,
 63→    direction: z > 0 ? "increase" : "decrease",
 64→  };
 65→}
