 98→export function projectPointsFromEvents(events: PointEvent[]): ProjectedPoint[] {
 99→  const groups = new Map<string, ProjectedPoint>();
100→  const sorted = [...events].sort((a, b) => new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime());
101→  for (const event of sorted) {
102→    const normalizedDetails = normalizeDetailsForCategory(event.category, event.details ?? {});
103→    const existing = groups.get(event.pointId);
104→    if (!existing) {
105→      groups.set(
106→        event.pointId,
107→        {
108→          id: event.pointId,
109→          pointId: event.pointId,
110→          category: event.category,
111→          location: event.location,
112→          details: normalizedDetails,
113→          photoUrl: event.photoUrl,
114→          createdAt: event.createdAt,
115→          updatedAt: event.createdAt,
116→          source: event.source,
117→          externalId: event.externalId,
118→          gaps: listMissingFields(event.category, normalizedDetails),
119→          eventsCount: 1,
120→          eventIds: [event.id],
121→        },
122→      );
123→      continue;
124→    }
125→
126→    existing.category = event.category;
127→    existing.location = event.location ?? existing.location;
128→    existing.details = mergeDetails(existing.details, normalizedDetails);
129→    existing.updatedAt = event.createdAt;
130→    existing.eventsCount += 1;
131→    existing.eventIds.push(event.id);
132→    if (event.photoUrl) existing.photoUrl = event.photoUrl;
133→    if (event.source) existing.source = event.source;
134→    if (event.externalId) existing.externalId = event.externalId;
135→    existing.gaps = listMissingFields(existing.category, existing.details);
136→  }
137→
138→  return Array.from(groups.values()).sort(
139→    (a, b) => new Date(b.updatedAt).getTime() - new Date(a.updatedAt).getTime(),
140→  );
141→}
