258→function toGpsLocation(latInput: unknown, lonInput: unknown): SubmissionLocation | null {
259→  const latitude = toFiniteNumber(latInput);
260→  const longitude = toFiniteNumber(lonInput);
261→  if (latitude === null || longitude === null) return null;
262→  return { latitude, longitude };
