610→export function buildPhotoFraudMetadata(params: BuildPhotoFraudMetadataParams): SubmissionPhotoMetadata | null {
611→  if (!params.extracted) return null;
612→
613→  const { extracted, submissionLocation, ipLocation, submissionMatchThresholdKm, ipMatchThresholdKm } = params;
614→  const gps = extracted.gps;
615→
616→  const submissionDistanceRaw = gps && submissionLocation ? haversineKm(submissionLocation, gps) : null;
617→  const ipDistanceRaw = gps && ipLocation ? haversineKm(ipLocation, gps) : null;
618→
619→  const submissionDistanceKm = submissionDistanceRaw === null ? null : roundKm(submissionDistanceRaw);
620→  const ipDistanceKm = ipDistanceRaw === null ? null : roundKm(ipDistanceRaw);
621→
622→  return {
623→    gps,
624→    capturedAt: extracted.capturedAt,
625→    deviceMake: extracted.deviceMake,
626→    deviceModel: extracted.deviceModel,
627→    submissionDistanceKm,
628→    submissionGpsMatch: submissionDistanceKm === null ? null : submissionDistanceKm <= submissionMatchThresholdKm,
629→    ipDistanceKm,
630→    ipGpsMatch: ipDistanceKm === null ? null : ipDistanceKm <= ipMatchThresholdKm,
631→    exifStatus: extracted.exifStatus,
632→    exifReason: extracted.exifReason,
633→    exifSource: extracted.exifSource,
634→  };
635→}
636→
637→export function buildSubmissionFraudCheck(params: BuildSubmissionFraudCheckParams): SubmissionFraudCheck {
638→  return {
639→    submissionLocation: params.submissionLocation,
640→    effectiveLocation: params.effectiveLocation,
641→    ipLocation: params.ipLocation,
642→    primaryPhoto: params.primaryPhoto,
643→    secondaryPhoto: params.secondaryPhoto,
644→    submissionMatchThresholdKm: params.submissionMatchThresholdKm,
645→    ipMatchThresholdKm: params.ipMatchThresholdKm,
646→  };
647→}
648→
649→function parsePhotoFraudMetadata(input: unknown): SubmissionPhotoMetadata | null {
650→  if (!input || typeof input !== "object") return null;
651→  const metadata = input as Record<string, unknown>;
652→
653→  const parsed: SubmissionPhotoMetadata = {
654→    gps: parseLocation(metadata.gps),
655→    capturedAt: parseDateIso(metadata.capturedAt),
656→    deviceMake: normalizeString(metadata.deviceMake),
657→    deviceModel: normalizeString(metadata.deviceModel),
658→    submissionDistanceKm: parseOptionalNumber(metadata.submissionDistanceKm),
659→    submissionGpsMatch: parseOptionalBoolean(metadata.submissionGpsMatch),
660→    ipDistanceKm: parseOptionalNumber(metadata.ipDistanceKm),
661→    ipGpsMatch: parseOptionalBoolean(metadata.ipGpsMatch),
662→    exifStatus: "missing",
663→    exifReason: normalizeString(metadata.exifReason),
664→    exifSource: parseExifSource(metadata.exifSource) ?? "none",
665→  };
666→
667→  const explicitStatus = parseExifStatus(metadata.exifStatus);
668→  if (explicitStatus) {
669→    parsed.exifStatus = explicitStatus;
670→  } else if (hasExifSignal(parsed)) {
671→    parsed.exifStatus = "ok";
672→  } else {
673→    parsed.exifStatus = "missing";
674→  }
675→
676→  return parsed;
677→}
678→
679→export function parseSubmissionFraudCheck(input: unknown): SubmissionFraudCheck | null {
680→  if (!input || typeof input !== "object") return null;
681→  const fraudCheck = input as Record<string, unknown>;
682→  const effectiveLocation = parseLocation(fraudCheck.effectiveLocation);
683→  if (!effectiveLocation) return null;
684→
685→  const submissionMatchThresholdKm =
686→    parseOptionalNumber(fraudCheck.submissionMatchThresholdKm) ?? DEFAULT_SUBMISSION_GPS_MATCH_THRESHOLD_KM;
687→  const ipMatchThresholdKm = parseOptionalNumber(fraudCheck.ipMatchThresholdKm) ?? 50;
688→
689→  return {
690→    submissionLocation: parseLocation(fraudCheck.submissionLocation),
691→    effectiveLocation,
692→    ipLocation: parseLocation(fraudCheck.ipLocation),
693→    primaryPhoto: parsePhotoFraudMetadata(fraudCheck.primaryPhoto),
694→    secondaryPhoto: parsePhotoFraudMetadata(fraudCheck.secondaryPhoto),
695→    submissionMatchThresholdKm,
696→    ipMatchThresholdKm,
697→  };
698→}
