484→export async function POST(request: Request): Promise<Response> {
485→  const auth = await requireUser(request);
486→  if (!auth) return errorResponse("Unauthorized", 401);
487→  const authContext = toSubmissionAuthContext(auth);
488→  const isAdminUser = authContext?.isAdmin === true;
489→
490→  let body: SubmissionInput;
491→  try {
492→    body = (await request.json()) as SubmissionInput;
493→  } catch {
494→    return errorResponse("Invalid JSON body", 400);
495→  }
496→
497→  const category = normalizeCategory(body?.category as string | undefined);
498→  if (!category) {
499→    return errorResponse("Invalid category", 400);
500→  }
501→
502→  const eventType = normalizeEventType(body?.eventType);
503→  const location = parseLocation(body?.location);
504→  const details = normalizeEnrichPayload(
505→    category,
506→    body?.details && typeof body.details === "object" ? ({ ...(body.details as SubmissionDetails) } as SubmissionDetails) : {},
507→  );
508→  const requestUserAgent = trimString(request.headers.get("user-agent"), 256);
509→  const clientDevice = sanitizeClientDevice((details as Record<string, unknown>).clientDevice);
510→  if (clientDevice) {
511→    if (!clientDevice.userAgent && requestUserAgent) clientDevice.userAgent = requestUserAgent;
512→    details.clientDevice = clientDevice;
513→  } else if ("clientDevice" in details) {
514→    delete details.clientDevice;
515→  }
516→
517→  const imageBase64 = body?.imageBase64 as string | undefined;
518→  if (!imageBase64) return errorResponse("Photo is required", 400);
519→  const parsedPhoto = parseImagePayload(imageBase64);
520→  if (!parsedPhoto) return errorResponse("Invalid photo format", 400);
521→  if (parsedPhoto.imageBuffer.byteLength > MAX_IMAGE_BYTES) {
522→    return errorResponse(`Photo exceeds maximum size of ${Math.round(MAX_IMAGE_BYTES / (1024 * 1024))}MB`, 400);
523→  }
524→
525→  const ipLocation = await getIpLocation(request);
526→  const clientExif = (body as unknown as Record<string, unknown>)?.clientExif as ClientExifData | null | undefined;
527→  let photoLocation: SubmissionLocation | null = null;
528→  let primaryPhotoMetadata: Awaited<ReturnType<typeof extractPhotoMetadata>> | null = null;
529→
530→  try {
531→    primaryPhotoMetadata = await extractPhotoMetadata(parsedPhoto.imageBuffer, {
532→      source: "upload_buffer",
533→      mime: parsedPhoto.mime,
534→      ext: parsedPhoto.ext,
535→      byteLength: parsedPhoto.imageBuffer.byteLength,
536→    });
537→    primaryPhotoMetadata = applyClientExifFallback(primaryPhotoMetadata, clientExif);
538→    if (primaryPhotoMetadata.gps) {
539→      photoLocation = primaryPhotoMetadata.gps;
540→      if (location) {
541→        const distance = haversineKm(location, photoLocation);
542→        if (distance > SUBMISSION_PHOTO_MATCH_KM) return errorResponse("Photo GPS coordinates do not match submission location", 400);
543→      }
544→      if (ipLocation) {
545→        const distance = haversineKm(ipLocation, photoLocation);
546→        if (distance > IP_PHOTO_MATCH_KM) return errorResponse("Photo location does not match IP location", 400);
547→      }
548→    } else if (!location && !ipLocation) {
549→      return errorResponse("Photo is missing GPS metadata", 400);
550→    }
551→  } catch {
552→    primaryPhotoMetadata = {
553→      gps: null,
554→      capturedAt: null,
555→      deviceMake: null,
556→      deviceModel: null,
557→      exifStatus: "parse_error",
558→      exifReason: `Unexpected EXIF extraction failure (mime=${parsedPhoto.mime}; ext=${parsedPhoto.ext}; bytes=${parsedPhoto.imageBuffer.byteLength})`,
559→      exifSource: "upload_buffer",
560→    };
561→    primaryPhotoMetadata = applyClientExifFallback(primaryPhotoMetadata, clientExif);
562→    if (!primaryPhotoMetadata.gps && !location && !ipLocation) {
563→      return errorResponse("Unable to read photo GPS metadata", 400);
564→    }
565→    if (primaryPhotoMetadata.gps) {
566→      photoLocation = primaryPhotoMetadata.gps;
567→    }
568→  }
569→
570→  const finalLocation = photoLocation ?? location ?? ipLocation;
571→  if (!finalLocation) return errorResponse("Missing or invalid location", 400);
572→  if (!isAdminUser && !isWithinBonamoussadi(finalLocation)) {
573→    return errorResponse(
574→      `Location outside Bonamoussadi bounds (${BONAMOUSSADI_BOUNDS.south},${BONAMOUSSADI_BOUNDS.west})-(${BONAMOUSSADI_BOUNDS.north},${BONAMOUSSADI_BOUNDS.east})`,
575→      400,
576→    );
577→  }
578→
579→  try {
580→    const existingEvents = await buildCombinedEvents();
581→    const projectedExisting = projectPointsFromEvents(existingEvents);
582→    let pointId = typeof body.pointId === "string" && body.pointId.trim() ? body.pointId.trim() : crypto.randomUUID();
583→
584→    if (eventType === "CREATE_EVENT") {
585→      const createError = validateCreatePayload(category, details);
586→      if (createError) return errorResponse(createError, 400);
587→    } else {
588→      if (!body.pointId || typeof body.pointId !== "string" || !body.pointId.trim()) {
589→        return errorResponse("pointId is required for ENRICH_EVENT", 400);
590→      }
591→      pointId = body.pointId.trim();
592→      const target = projectedExisting.find((point) => point.pointId === pointId);
593→      if (!target) return errorResponse("Target point not found", 404);
594→      if (target.category !== category) return errorResponse("Category mismatch for target point", 400);
595→
596→      const submittedEntries = Object.entries(details).filter(([, value]) => hasValue(value));
597→      const allowedGaps = new Set(target.gaps);
598→      const filteredEntries = submittedEntries.filter(([field]) => {
599→        const canonical =
600→          field === "hours"
601→            ? "openingHours"
602→            : field === "merchantId"
603→              ? "merchantIdByProvider"
604→              : field === "hasCashAvailable"
605→                ? "hasMin50000XafAvailable"
606→                : field;
607→        return isEnrichFieldAllowed(category, canonical) && allowedGaps.has(canonical);
608→      });
609→      if (!filteredEntries.length) {
610→        return errorResponse("ENRICH_EVENT must include at least one currently missing field", 400);
611→      }
612→      const filteredDetails: SubmissionDetails = {};
613→      for (const [key, value] of filteredEntries) {
614→        filteredDetails[key] = value;
615→      }
616→      Object.assign(details, filteredDetails);
617→      for (const key of Object.keys(details)) {
618→        if (!Object.prototype.hasOwnProperty.call(filteredDetails, key)) {
619→          delete details[key];
620→        }
621→      }
622→      if (clientDevice) {
623→        details.clientDevice = clientDevice;
624→      }
625→    }
626→
627→    const eventId = crypto.randomUUID();
628→    let photoUrl: string | undefined;
629→    try {
630→      photoUrl = await uploadSubmissionPhoto(eventId, parsedPhoto.imageBuffer, parsedPhoto.mime, parsedPhoto.ext);
631→    } catch (error) {
632→      const raw = error instanceof Error ? error.message : String(error);
633→      const lower = raw.toLowerCase();
634→      if (lower.includes("blob") && lower.includes("token")) return errorResponse("Blob storage is not configured", 500);
635→      return errorResponse("Unable to store photo", 500);
636→    }
637→    details.hasPhoto = true;
638→
639→    let secondaryPhotoMetadata: Awaited<ReturnType<typeof extractPhotoMetadata>> | null = null;
640→    const secondImageBase64 = body?.secondImageBase64 as string | undefined;
641→    if (secondImageBase64) {
642→      const parsedSecondPhoto = parseImagePayload(secondImageBase64);
643→      if (!parsedSecondPhoto) return errorResponse("Invalid photo format", 400);
644→      if (parsedSecondPhoto.imageBuffer.byteLength > MAX_IMAGE_BYTES) {
645→        return errorResponse(`Photo exceeds maximum size of ${Math.round(MAX_IMAGE_BYTES / (1024 * 1024))}MB`, 400);
646→      }
647→
648→      try {
649→        secondaryPhotoMetadata = await extractPhotoMetadata(parsedSecondPhoto.imageBuffer, {
650→          source: "upload_buffer",
651→          mime: parsedSecondPhoto.mime,
652→          ext: parsedSecondPhoto.ext,
653→          byteLength: parsedSecondPhoto.imageBuffer.byteLength,
654→        });
655→      } catch {
656→        secondaryPhotoMetadata = {
657→          gps: null,
658→          capturedAt: null,
659→          deviceMake: null,
660→          deviceModel: null,
661→          exifStatus: "parse_error",
662→          exifReason: `Unexpected EXIF extraction failure (mime=${parsedSecondPhoto.mime}; ext=${parsedSecondPhoto.ext}; bytes=${parsedSecondPhoto.imageBuffer.byteLength})`,
663→          exifSource: "upload_buffer",
664→        };
665→      }
666→
667→      try {
668→        const secondPhotoUrl = await uploadSubmissionPhoto(
669→          `${eventId}-second`,
670→          parsedSecondPhoto.imageBuffer,
671→          parsedSecondPhoto.mime,
672→          parsedSecondPhoto.ext,
673→        );
674→        details.secondPhotoUrl = secondPhotoUrl;
675→        details.hasSecondaryPhoto = true;
676→      } catch {
677→        return errorResponse("Unable to store photo", 500);
678→      }
679→    }
680→
681→    const primaryPhotoFraud = buildPhotoFraudMetadata({
682→      extracted: primaryPhotoMetadata,
683→      submissionLocation: location,
684→      ipLocation,
685→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
686→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
687→    });
688→    const secondaryPhotoFraud = buildPhotoFraudMetadata({
689→      extracted: secondaryPhotoMetadata,
690→      submissionLocation: location,
691→      ipLocation,
692→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
693→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
694→    });
695→    details.fraudCheck = buildSubmissionFraudCheck({
696→      submissionLocation: location,
697→      effectiveLocation: finalLocation,
698→      ipLocation,
699→      primaryPhoto: primaryPhotoFraud,
700→      secondaryPhoto: secondaryPhotoFraud,
701→      submissionMatchThresholdKm: SUBMISSION_PHOTO_MATCH_KM,
702→      ipMatchThresholdKm: IP_PHOTO_MATCH_KM,
703→    });
704→
705→    const now = new Date().toISOString();
706→    const newEvent: PointEvent = {
707→      id: eventId,
708→      pointId,
709→      eventType,
710→      userId: auth.id,
711→      category,
712→      location: finalLocation,
713→      details,
714→      photoUrl,
715→      createdAt: now,
716→      source: typeof details.source === "string" ? details.source : undefined,
717→      externalId: typeof details.externalId === "string" ? details.externalId : undefined,
718→    };
719→
720→    await insertPointEvent(newEvent);
721→
722→    const exifDeviceMake = primaryPhotoMetadata?.deviceMake ?? null;
723→    const exifDeviceModel = primaryPhotoMetadata?.deviceModel ?? null;
724→    const logPayload = {
725→      eventId,
726→      userId: auth.id,
727→      category,
728→      deviceId: clientDevice?.deviceId ?? null,
729→      clientPlatform: clientDevice?.platform ?? null,
730→      clientUserAgent: clientDevice?.userAgent ?? requestUserAgent ?? null,
731→      clientMemoryGb: clientDevice?.deviceMemoryGb ?? null,
732→      clientCpuCores: clientDevice?.hardwareConcurrency ?? null,
733→      clientIsLowEnd: clientDevice?.isLowEnd ?? null,
734→      exifDeviceMake,
735→      exifDeviceModel,
736→    };
737→    if (process.env.NODE_ENV !== "production") {
738→      console.info("[SUBMISSION_DEVICE]", JSON.stringify(logPayload));
